import { describe, it, expect } from "vitest";
import { execute } from "./mars-rover.js";

describe("Mars Rover", () => {
  it("should return the initial position and heading for an empty command string", () => {
    expect(execute("")).toBe("0:0:N");
  });
  it.todo("should rotate left from north to west");
  it.todo("should rotate right from north to east");
  it.todo("should move forward one square when facing north");
  it.todo("should move forward one square when facing east");
  it.todo("should move forward one square when facing south");
  it.todo("should move forward one square when facing west");
  it.todo("should rotate left through all four headings (N->W->S->E->N)");
  it.todo("should rotate right through all four headings (N->E->S->W->N)");
  it.todo("should execute a sequence of commands in order");
});
